class Solution {
public:
    int maxTaskAssign(vector<int>& tasks, vector<int>& workers, int pills, int strength) {
        sort(tasks.begin(), tasks.end());
        sort(workers.begin(), workers.end());
        int n = tasks.size(), m = workers.size();
        int left = 0, right = min(n, m);
        while (left < right) {
            int mid = left + (right - left + 1) / 2;
            if (check(mid, tasks, workers, pills, strength)) {
                left = mid;
            } else {
                right = mid - 1;
            }
        }
        return left;
    }

private:
    bool check(int k, const vector<int>& tasks, const vector<int>& workers, int pills, int strength) {
        multiset<int> ws;
        int m = workers.size();
        for (int i = m - k; i < m; ++i) {
            ws.insert(workers[i]);
        }
        int p = pills;
        for (int i = k - 1; i >= 0; --i) {
            int t = tasks[i];
            auto it = ws.lower_bound(t);
            if (it != ws.end()) {
                ws.erase(it);
            } else {
                if (p == 0) return false;
                it = ws.lower_bound(t - strength);
                if (it == ws.end()) return false;
                ws.erase(it);
                --p;
            }
        }
        return true;
    }
};
```
efficiency: HIGH
time complexity: O((n + m) log n log m)
space complexity: O(m)
energy implications: LOW
explanation: Binary search on the maximum number of tasks k. For each candidate k, use the k smallest tasks and the k strongest workers. Greedy matching with a multiset: assign the smallest adequate worker to each task; if none exists, use a pill on the smallest worker that can handle the task after the boost.

